const messages = rows.map(r=>{let mediaUrl=r.media_url||null;const blob=(r.has_blob===true||r.has_blob==='true'||r.has_blob==='t');if(!mediaUrl&&blob)mediaUrl=BASE+'/webhook/wa-media?id='+r.id;return {id:String(r.id),conversationId:String(r.conversation_id),direction:r.direction,type:r.type||'text',text:r.text||'',template:r.template||null,mediaUrl,mediaMime:r.media_mime||null,mediaFilename:r.media_filename||null,timestamp:Number(r.timestamp)||0,status:r.status||'received',channel:r.channel||'whatsapp'};});
return [{ json: { messages } }];
